module top_module(
  input [31:0] data_in,
  input [15:0] mask,
  input enable,
  output [15:0] data_out
);reg [15:0] obf_temp_data_out;

  always @(*) begin
    if (enable) begin
      obf_temp_data_out = data_in & mask;
    end else begin
      obf_temp_data_out = 16'b0;
    end
  end

  assign data_out = obf_temp_data_out;

endmodule
